/**
 * WAB Client — Zero-setup protocol client for AI agent ↔ website interaction
 * https://webagentbridge.com
 * License: MIT
 */
(function(global) {
  'use strict';

  var VERSION = '1.2.0';

  function WABInstance(config) {
    this.name = config.name || document.title || 'WAB Site';
    this.actions = {};
    this.log = [];
    this._ready = false;

    if (config.actions) {
      for (var key in config.actions) {
        if (config.actions.hasOwnProperty(key)) {
          var action = config.actions[key];
          if (typeof action === 'function') {
            this.actions[key] = { description: key, run: action };
          } else {
            this.actions[key] = {
              description: action.description || key,
              params: action.params || [],
              run: action.run || function() { return { success: false, error: 'no handler' }; }
            };
          }
        }
      }
    }

    global.__wab_protocol = {
      version: VERSION,
      protocol: '1.0',
      name: this.name,
      actions: Object.keys(this.actions).map(function(k) {
        return { name: k, description: this.actions[k].description };
      }.bind(this)),
      transport: ['javascript', 'http'],
      ready: true
    };

    if (global.AICommands && typeof global.AICommands.registerAction === 'function') {
      for (var name in this.actions) {
        if (this.actions.hasOwnProperty(name)) {
          global.AICommands.registerAction(name, this.actions[name].description, this.actions[name].run);
        }
      }
    }

    this._ready = true;
  }

  WABInstance.prototype.discover = function() {
    var actionList = [];
    for (var key in this.actions) {
      if (this.actions.hasOwnProperty(key)) {
        actionList.push({ name: key, description: this.actions[key].description });
      }
    }
    return Promise.resolve({
      wab_version: VERSION,
      name: this.name,
      actions: actionList,
      transport: ['javascript', 'http']
    });
  };

  WABInstance.prototype.execute = function(actionName, params) {
    var action = this.actions[actionName];
    if (!action) {
      return Promise.resolve({ success: false, error: 'Action not found: ' + actionName });
    }
    try {
      var result = action.run(params || {});
      if (result && typeof result.then === 'function') {
        return result;
      }
      return Promise.resolve(result);
    } catch (e) {
      return Promise.resolve({ success: false, error: e.message });
    }
  };

  WABInstance.prototype.getActions = function() {
    return Object.keys(this.actions);
  };

  var WAB = {
    version: VERSION,
    init: function(config) {
      var instance = new WABInstance(config || {});
      global.WAB._instance = instance;
      return instance;
    },
    _instance: null
  };

  global.WAB = WAB;

})(typeof window !== 'undefined' ? window : this);
